120	ThreadContext *
121	System::Threads::findFree()
122	{
123	    for (auto &thread: threads) {
124	        if (thread.context->status() == ThreadContext::Halted)
125	            return thread.context;
126	    }
127	    return nullptr;
128	}
129	
130	int
131	System::Threads::numRunning() const
132	{
133	    int count = 0;
134	    for (auto &thread: threads) {
135	        auto status = thread.context->status();
136	        if (status != ThreadContext::Halted &&
137	                status != ThreadContext::Halting) {
138	            count++;
139	        }
140	    }
141	    return count;
142	}
