167	System::System(const Params &p)
168	    : SimObject(p), _systemPort("system_port"),
169	      externalMemRanges(p.external_memory_ranges.begin(),
170	                         p.external_memory_ranges.end()),
171	      multiThread(p.multi_thread),
172	      init_param(p.init_param),
173	      physProxy(_systemPort, p.cache_line_size),
174	      workload(p.workload),
175	      physmem(name() + ".physmem", p.memories, p.mmap_using_noreserve,
176	              p.shared_backstore, p.auto_unlink_shared_backstore),
177	      ShadowRomRanges(p.shadow_rom_ranges.begin(),
178	                      p.shadow_rom_ranges.end()),
179	      memoryMode(p.mem_mode),
180	      _cacheLineSize(p.cache_line_size),
181	      numWorkIds(p.num_work_ids),
182	      thermalModel(p.thermal_model),
183	      _m5opRange(p.m5ops_base ?
184	                 RangeSize(p.m5ops_base, 0x10000) :
185	                 AddrRange(1, 0)), // Create an empty range if disabled
186	      redirectPaths(p.redirect_paths)
187	{
188	    panic_if(!workload, "No workload set for system %s "
189	            "(could use StubWorkload?).", name());
190	    workload->setSystem(this);
191	
192	    // add self to global system list
193	    systemList.push_back(this);
194	
195	    // check if the cache line size is a value known to work
196	    if (_cacheLineSize != 16 && _cacheLineSize != 32 &&
197	        _cacheLineSize != 64 && _cacheLineSize != 128) {
198	        warn_once("Cache line size is neither 16, 32, 64 nor 128 bytes.\n");
199	    }
200	
201	    // Get the generic system requestor IDs
202	    [[maybe_unused]] RequestorID tmp_id;
203	    tmp_id = getRequestorId(this, "writebacks");
204	    assert(tmp_id == Request::wbRequestorId);
205	    tmp_id = getRequestorId(this, "functional");
206	    assert(tmp_id == Request::funcRequestorId);
207	    tmp_id = getRequestorId(this, "interrupt");
208	    assert(tmp_id == Request::intRequestorId);
209	
210	    // increment the number of running systems
211	    numSystemsRunning++;
212	
213	    // Set back pointers to the system in all memories
214	    for (int x = 0; x < params().memories.size(); x++)
215	        params().memories[x]->system(this);
216	}
