269	void
270	System::replaceThreadContext(ThreadContext *tc, ContextID context_id)
271	{
272	    auto *otc = threads[context_id];
273	    threads.replace(tc, context_id);
274	
275	    workload->replaceThreadContext(tc);
276	
277	    for (auto *e: liveEvents) {
278	        otc->remove(e);
279	        tc->schedule(e);
280	    }
281	}
