289	bool
290	System::isMemAddr(Addr addr) const
291	{
292	    if (physmem.isMemAddr(addr)) {
293	        return true;
294	    } else {
295	        // Check the external memory ranges as well
296	        for (const auto& range : externalMemRanges) {
297	            if (range.contains(addr)) {
298	                return true;
299	            }
300	        }
301	
302	        return false;
303	    }
304	}
