323	memory::AbstractMemory *
324	System::getDeviceMemory(const PacketPtr& pkt) const
325	{
326	    const RequestorID& rid = pkt->requestorId();
327	
328	    panic_if(!deviceMemMap.count(rid),
329	             "No device memory found for Requestor %d\n", rid);
330	
331	    for (auto& mem : deviceMemMap.at(rid)) {
332	        if (pkt->getAddrRange().isSubset(mem->getAddrRange())) {
333	            return mem;
334	        }
335	    }
336	
337	    return nullptr;
338	}
