340	void
341	System::serialize(CheckpointOut &cp) const
342	{
343	    for (auto &t: threads.threads) {
344	        Tick when = 0;
345	        if (t.resumeEvent && t.resumeEvent->scheduled())
346	            when = t.resumeEvent->when();
347	        ContextID id = t.context->contextId();
348	        paramOut(cp, csprintf("quiesceEndTick_%d", id), when);
349	    }
350	
351	    // also serialize the memories in the system
352	    physmem.serializeSection(cp, "physmem");
353	}
354	
355	
356	void
357	System::unserialize(CheckpointIn &cp)
358	{
359	    for (auto &t: threads.threads) {
360	        Tick when = 0;
361	        ContextID id = t.context->contextId();
362	        if (!optParamIn(cp, csprintf("quiesceEndTick_%d", id), when) ||
363	                !when || !t.resumeEvent) {
364	            continue;
365	        }
366	        t.context->getCpuPtr()->schedule(t.resumeEvent, when);
367	    }
368	
369	    // also unserialize the memories in the system
370	    physmem.unserializeSection(cp, "physmem");
371	}
