721	void
722	BaseCPU::flushTLBs()
723	{
724	    for (ThreadID i = 0; i < threadContexts.size(); ++i) {
725	        ThreadContext &tc(*threadContexts[i]);
726	        CheckerCPU *checker(tc.getCheckerCpuPtr());
727	
728	        tc.getMMUPtr()->flushAll();
729	        if (checker) {
730	            checker->getMMUPtr()->flushAll();
731	        }
732	    }
733	}
