795	bool
796	AddressMonitor::doMonitor(PacketPtr pkt)
797	{
798	    assert(pkt->req->hasPaddr());
799	    if (armed && waiting) {
800	        if (pAddr == pkt->getAddr()) {
801	            DPRINTF(Mwait, "pAddr=0x%lx invalidated: waking up core\n",
